/// Creates an `EditorViewModel` with test defaults (a fresh `AppState` and
/// `MockPersistenceService`), avoiding the old `NSApp.delegate` lookup (ISS-056).
@MainActor
private func makeTestEditorViewModel() -> EditorViewModel {
    EditorViewModel(appState: AppState(), persistenceService: MockPersistenceService())
}

private func writeTempFile(content: String, name: String) throws -> URL {
    let url = FileManager.default.temporaryDirectory.appendingPathComponent(name)
    try content.write(to: url, atomically: true, encoding: .utf8)
    return url
}

@MainActor
private func makeSolidImage(color: NSColor, size: CGSize) -> NSImage {
    let image = NSImage(size: size)
    image.lockFocus()
    color.setFill()
    NSRect(origin: .zero, size: size).fill()
    image.unlockFocus()
    return image
}

