// MARK: - EditorViewModelTests

@MainActor
struct EditorViewModelTests {

    // MARK: Happy Path

    @Test func openDocumentInfersMarkdownModeFromExtension() async throws {
        let url = try writeTempFile(content: "# Hello", name: "evm_md.md")
